/**
 * Renders a selectable payment-style tab with checkbox semantics.
 */
export default function CheckboxTab({
  title,
  description,
  iconName = "card",
  checked,
  disabled = false,
  className,
  containerClassName,
  onChange,
  ...props
}: CheckboxTabPropsData) {
  // Define Navigation

  // Define Context

  // Define Refs

  // Define States

  // Helper Functions
  function handleChange(event: ChangeEvent<HTMLInputElement>): void {
    onChange?.(event);
  }

  // Use Effects

  return (
    <label
      className={joinClasses(
        "border-n-400 bg-n-50 relative flex w-full flex-col gap-3 rounded-xl border border-[1px] p-3 text-left transition-[transform,border-color,box-shadow] duration-300 ease-[cubic-bezier(0.22,1,0.36,1)]",
        disabled
          ? "cursor-not-allowed opacity-60"
          : "cursor-pointer hover:scale-[1.01] hover:cursor-pointer hover:shadow-[0_10px_24px_rgba(14,23,43,0.08)]",
        containerClassName,
      )}
    >
      <input
        {...props}
        type="checkbox"
        checked={checked}
        disabled={disabled}
        onChange={handleChange}
        className={joinClasses("peer sr-only", className)}
      />

      <div className={joinClasses("h-7 w-7 shrink-0", checked ? "text-n-900" : "text-n-700")}>
        {renderPaymentIcon(iconName)}
      </div>

      <div className="flex w-full flex-col gap-0.5 pr-10">
        <span className={joinClasses("text-lg leading-normal font-semibold", checked ? "text-n-900" : "text-n-700")}>
          {title}
        </span>
        <span
          className={joinClasses(
            "text-sm leading-normal",
            checked ? "text-n-500 font-normal" : "text-n-600 font-normal",
          )}
        >
          {description}
        </span>
      </div>

      {renderCheckIndicator({ checked: Boolean(checked) })}

      <span className="peer-focus-visible:ring-offset-n-50 pointer-events-none absolute inset-0 rounded-xl ring-0 ring-transparent transition peer-focus-visible:ring-2 peer-focus-visible:ring-blue-500 peer-focus-visible:ring-offset-2" />
    </label>
  );
}
